import json, glob
from collections import Counter

files = sorted(glob.glob("session_*.json"))

# Extract user communication patterns
user_starts = []  # how users start conversations
user_questions = []  # types of questions asked
assistant_roles = []  # how AI is positioned

for f in files:
    try:
        with open(f) as fp:
            d = json.load(fp)
        msgs = d.get('messages', [])

        # First user message (after greeting exchange)
        for i, m in enumerate(msgs[:5]):
            if m.get('role') == 'user' and str(m.get('content','')) not in ['您好', '请说中文', '你好', 'Hi', 'hello']:
                user_starts.append(str(m.get('content',''))[:100])
                break

        # Count question types
        for m in msgs:
            if m.get('role') == 'user':
                c = str(m.get('content',''))
                if c.startswith('能不能') or '能不能' in c:
                    user_questions.append(('能不能', c[:150]))
                if c.startswith('帮我') or '帮我' in c:
                    user_questions.append(('帮我', c[:150]))
                if '?' in c or '？' in c:
                    user_questions.append(('question', c[:150]))
    except:
        pass

print("=== USER STARTS (first meaningful message per session) ===\n")
starts = Counter(user_starts)
for msg, count in starts.most_common(15):
    print(f"[{count}] {msg}")
